    #[test]
    fn test_is_running() {
        // We'll test the actual logic of the is_running method here
        // which is "started but not finished"

        // Create a mock implementation for testing
        struct MockState {
            started: bool,
            finished: bool,
        }

        impl MockState {
            fn is_started(&self) -> bool {
                self.started
            }

            fn is_finished(&self) -> bool {
                self.finished
            }
        }

        // Test different combinations of started and finished states

        // Case 1: Not started, not finished
        let state = MockState { started: false, finished: false };
        let is_running = state.is_started() && !state.is_finished();
        assert_eq!(is_running, false);

        // Case 2: Started, not finished
        let state = MockState { started: true, finished: false };
        let is_running = state.is_started() && !state.is_finished();
        assert_eq!(is_running, true);

        // Case 3: Started and finished
        let state = MockState { started: true, finished: true };
        let is_running = state.is_started() && !state.is_finished();
        assert_eq!(is_running, false);

        // Case 4: Not started but finished (invalid but testing logic)
        let state = MockState { started: false, finished: true };
        let is_running = state.is_started() && !state.is_finished();
        assert_eq!(is_running, false);
    }
}

