        // Create a keypair
        let keypair = Keypair::generate();
        let public_key = keypair.public();

        // Test data
        let message = b"test message";

        // Sign the message
        let mut signature = keypair.sign(message);

        // Corrupt the signature
        signature[0] = signature[0].wrapping_add(1);

        // Verify the corrupted signature (should fail)
        let result = public_key.verify(message, &signature);
        assert!(!result);
    }

