pub fn verify(&self, msg: &[u8], sig: &[u8]) -> bool {
    if sig.len() != 64 {
        return false;
    }

    match ed25519::Signature::try_from(sig) {
        Ok(signature) => self.0.verify(msg, &signature).is_ok(),
        Err(_) => false
    }
}

