pub(crate) fn put(&mut self, message_id: &MessageId, msg: RawMessage) -> bool {
    let is_new = !self.msgs.contains_key(message_id);

    // Always update the message, overwriting any existing one with the same ID
    // This matches Python's behavior of: self.msgs[mid] = msg
    self.msgs.insert(message_id.clone(), (msg.clone(), HashSet::new()));

    self.history[0].push(CacheEntry {
        mid: message_id.clone(),
        topic: msg.topic.clone(),
    });

    is_new
}

