    // Create a message ID
    let source_bytes = message.source.as_ref().unwrap().to_bytes();
    let seq_bytes = message.sequence_number.unwrap().to_be_bytes().to_vec();
    let mut id_bytes = source_bytes;
    id_bytes.extend_from_slice(&seq_bytes);
    let message_id = MessageId::new(&id_bytes);

    // Test getting a message that doesn't exist yet
    let result = cache.get(&message_id);
    assert!(result.is_none());

    // Put the message in the cache
    cache.put(&message_id, message.clone());

    // Get the message from the cache
    let result = cache.get(&message_id);
    assert!(result.is_some());
    assert_eq!(result.unwrap(), &message);

    // Try to get a message with an incorrect ID
    let wrong_id = MessageId::new(b"wrongid");
    let missing_result = cache.get(&wrong_id);
    assert!(missing_result.is_none());
}

