from libp2p.tools.async_service.base import as_service


class TestIterMethod(unittest.TestCase):
    def test_iter_method_yields_cache_keys(self):
        # Create a simple mock class that has a cache with keys
        class MockService:
            def __init__(self):
                self.cache = {
                    'key1': 'value1',
                    'key2': 'value2',
                    'key3': 'value3',
                }

            def iter(self):
                for key in self.cache.keys():
                    yield key

        # Create an instance of the mock service
        service = MockService()

        # Test that the iter method yields all keys from the cache
        keys_from_iter = list(service.iter())
        cache_keys = list(service.cache.keys())

        # Verify that the iter method yields exactly the keys from the cache
        self.assertEqual(sorted(keys_from_iter), sorted(cache_keys))

        # Verify the iter method returns a generator
        self.assertTrue(hasattr(service.iter(), '__next__'))

    def test_iter_method_with_empty_cache(self):
        # Create a mock service with empty cache
        class MockServiceEmpty:
            def __init__(self):
                self.cache = {}

            def iter(self):
                for key in self.cache.keys():
                    yield key

        # Create an instance of the mock service with empty cache
        service = MockServiceEmpty()

        # Test that iter method yields nothing when cache is empty
        keys_from_iter = list(service.iter())
        self.assertEqual(len(keys_from_iter), 0)


